import React, { useMemo, useState } from "react";

const ContenedorLateral = ({
  subtitulo,
  imagen,
  ancho,
  alto,
  ovaloRedondez,
  cuadroRedondez,
  dias,
}) => {
  // Construye días por defecto: hoy, mañana y pasado
  const defaultDias = useMemo(() => {
    const base = new Date();
    const toISODate = (d) => {
      const y = d.getFullYear();
      const m = String(d.getMonth() + 1).padStart(2, "0");
      const day = String(d.getDate()).padStart(2, "0");
      return `${y}-${m}-${day}`;
    };
    const d1 = new Date(base);
    const d2 = new Date(base); d2.setDate(base.getDate() + 1);
    const d3 = new Date(base); d3.setDate(base.getDate() + 2);
    return [
      { label: "Día 1", date: toISODate(d1), imageUrl: imagen },
      { label: "Día 2", date: toISODate(d2), imageUrl: imagen },
      { label: "Día 3", date: toISODate(d3), imageUrl: imagen },
    ];
  }, [imagen]);

  const diasData = dias && Array.isArray(dias) && dias.length === 3 ? dias : defaultDias;

  // Selecciona el día según la fecha actual
  const todayISO = useMemo(() => {
    const t = new Date();
    const y = t.getFullYear();
    const m = String(t.getMonth() + 1).padStart(2, "0");
    const d = String(t.getDate()).padStart(2, "0");
    return `${y}-${m}-${d}`;
  }, []);

  const initialIndex = Math.max(0, diasData.findIndex((d) => d.date === todayISO));
  const [activeIdx, setActiveIdx] = useState(initialIndex === -1 ? 0 : initialIndex);

  const getStatus = (dateISO) => {
    if (dateISO === todayISO) return "Hoy";
    return dateISO < todayISO ? "Realizado" : "Próximamente";
  };

  return (
    <div
      className="relative flex flex-col z-10 ml-auto bg-surface-elevated border border-stroke"
      style={{
        width: ancho,
        height: alto,
        borderColor: "#072D42",
        borderWidth: "clamp(2px, 0.618vh, 4px)",
        borderStyle: "solid",
        borderRadius: `0 ${cuadroRedondez} ${cuadroRedondez} 0`,
        marginTop: "clamp(2rem, 6.18vh, 4rem)",
        overflow: "hidden",
      }}
    >
      {/* Header */}
      <div className="px-4 md:px-6 lg:px-8 py-3 md:py-4 lg:py-5 border-b border-stroke bg-surface-elevated/90 backdrop-blur-sm">
        <h2 className="font-bodoni tracking-wider uppercase text-primary text-lg md:text-xl lg:text-2xl text-center">
          {subtitulo || "Semana de actividades"}
        </h2>
      </div>

      {/* Selector de días */}
      <div className="px-3 md:px-6 lg:px-8 py-3">
        <div className="grid grid-cols-3 gap-2 md:gap-3">
          {diasData.map((d, idx) => {
            const status = getStatus(d.date);
            const isActive = idx === activeIdx;
            return (
              <button
                key={d.label}
                onClick={() => setActiveIdx(idx)}
                className={`group flex flex-col items-center justify-center rounded-md border transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-primary/40 ${
                  isActive
                    ? "bg-primary text-white border-primary shadow-sm"
                    : "bg-surface text-text-main border-stroke hover:bg-surface/80"
                } py-2 md:py-3`}
                aria-pressed={isActive}
              >
                <span className={`font-miles text-xs md:text-sm ${isActive ? "opacity-100" : "opacity-90"}`}>{d.label}</span>
                <span
                  className={`mt-1 inline-flex items-center rounded-full px-2 py-0.5 text-[10px] md:text-xs border ${
                    status === "Hoy"
                      ? "bg-white/10 border-white/30 text-white"
                      : status === "Realizado"
                      ? "bg-green-50 text-green-700 border-green-200"
                      : "bg-amber-50 text-amber-700 border-amber-200"
                  }`}
                >
                  {status}
                </span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Contenido */}
      <div className="flex-1 px-4 md:px-6 lg:px-8 pb-6 flex items-center justify-center">
        <div className="relative w-full max-w-[720px] h-full flex items-center justify-center">
          <div className="relative w-[min(90%,640px)] h-[min(60%,420px)] md:w-[min(90%,700px)] md:h-[min(65%,480px)] lg:w-[min(88%,720px)] lg:h-[min(68%,520px)] overflow-hidden rounded-lg border border-stroke bg-surface">
            <img
              src={diasData[activeIdx]?.imageUrl || imagen}
              alt={`${diasData[activeIdx]?.label || "Día"} - imagen`}
              className="w-full h-full object-cover"
            />
            {/* Sutil gradiente inferior para legibilidad si se agregan textos luego */}
            <div className="pointer-events-none absolute inset-x-0 bottom-0 h-16 bg-gradient-to-t from-black/10 to-transparent" />
          </div>
        </div>
      </div>
    </div>
  );
};

export default ContenedorLateral;
